from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    subject_map = {}
    for triple in triples:
        if triple.subject not in subject_map:
            subject_map[triple.subject] = []
        subject_map[triple.subject].append((triple.predicate, triple.object))

    sentence = ""
    for subject, triples in subject_map.items():
        if sentence:
            sentence += " which "
        sentence += f"{subject} "

        # Group related information for better flow
        city_served = None
        country = None
        location = None
        runway_info = []
        elevation_info = []
        identifiers = []
        other_info = []

        for predicate, obj in triples:
            if predicate == "cityServed":
                city_served = obj
            elif predicate == "country":
                country = obj
            elif predicate == "location":
                location = obj
            elif predicate == "elevationAboveTheSeaLevel":
                elevation_info.append(f"{obj} metres above sea level")
            elif predicate == "elevationAboveTheSeaLevelInFeet":
                elevation_info.append(f"{obj} feet above sea level")
            elif predicate == "runwayLength":
                runway_info.append(f"runway of {obj} metres")
            elif predicate == "1stRunwayLengthFeet":
                runway_info.append(f"first runway of {obj} feet")
            elif predicate == "1stRunwayLengthMetre":
                runway_info.append(f"first runway of {obj} metres")
            elif predicate == "3rdRunwayLengthFeet":
                runway_info.append(f"third runway of {obj} feet")
            elif predicate == "1stRunwaySurfaceType":
                runway_info.append(f"first runway surface: {obj}")
            elif predicate == "2ndRunwaySurfaceType":
                runway_info.append(f"second runway surface: {obj}")
            elif predicate == "3rdRunwaySurfaceType":
                runway_info.append(f"third runway surface: {obj}")
            elif predicate == "4thRunwaySurfaceType":
                runway_info.append(f"fourth runway surface: {obj}")
            elif predicate == "5thRunwaySurfaceType":
                runway_info.append(f"fifth runway surface: {obj}")
            elif predicate == "runwaySurfaceType":
                runway_info.append(f"runway surface: {obj}")
            elif predicate == "icaoLocationIdentifier":
                identifiers.append(f"ICAO code {obj}")
            elif predicate == "iataLocationIdentifier":
                identifiers.append(f"IATA code {obj}")
            elif predicate == "locationIdentifier":
                identifiers.append(f"location identifier {obj}")
            elif predicate == "nativeName":
                other_info.append(f"also known as {obj}")
            elif predicate == "operatingOrganisation":
                other_info.append(f"operated by {obj}")
            elif predicate == "owner":
                other_info.append(f"owned by {obj}")
            elif predicate == "mayor":
                other_info.append(f"has a mayor of {obj}")
            elif predicate == "capital":
                other_info.append(f"has {obj} as its capital")
            elif predicate == "language":
                other_info.append(f"has an official language of {obj}")
            elif predicate == "leader":
                other_info.append(f"has {obj} as its leader")
            elif predicate == "leaderParty":
                other_info.append(f"led by {obj}")
            elif predicate == "isPartOf":
                other_info.append(f"is part of {obj}")
            elif predicate == "runwayName":
                runway_info.append(f"runway named {obj}")
            else:
                other_info.append(f"has {predicate.replace('1stRunway', 'first runway').replace('2ndRunway', 'second runway').replace('3rdRunway', 'third runway').replace('4thRunway', 'fourth runway').replace('5thRunway', 'fifth runway')} of {obj}")

        # Build sentence with logical flow
        parts = []

        # Start with city served if available
        if city_served:
            parts.append(f"serves the city of {city_served}")

        # Add location information
        if location:
            parts.append(f"is located in {location}")

        # Add country information
        if country and city_served:
            # If we have cityServed and country, connect them naturally
            if "serves the city of" in parts[0]:
                city_name = city_served.split(",")[0] if "," in city_served else city_served
                parts[0] = f"serves {city_name}, which is in {country}"
            else:
                parts.append(f"is located in {country}")
        elif country:
            parts.append(f"is located in {country}")

        # Add elevation
        if elevation_info:
            parts.append(f"has an elevation of {elevation_info[0]}")

        # Add runway information
        if runway_info:
            parts.append(f"has " + ", ".join(runway_info))

        # Add identifiers
        if identifiers:
            parts.append(f"with {', '.join(identifiers)}")

        # Add other information
        if other_info:
            parts.extend(other_info)

        # Join all parts
        if parts:
            sentence += ", ".join(parts)

    return sentence + "."

